        if (noteKey.current) return;

        // Makes sure the node is a note
        console.log(ops);
        const noteOp = ops[1];
        if (!isInsertEmbedOpOfType('note', noteOp)) return;
        const noteElement = editorRef.current?.getElementByKey(insertedNodeKey);
